+        // Helper to parse boolean strings (mirrors get_bool logic)
+        fn parse_bool_string(value: &str) -> Option<bool> {
+            match value.to_lowercase().as_str() {
+                "1" | "true" | "yes" | "on" => Some(true),
+                "0" | "false" | "no" | "off" | "" => Some(false),
